import os
import json
import pymysql
from google.cloud import secretmanager

# Connection pooling - reuse across invocations
db_connection = None

ALLOWED_COLUMNS = {
    "users": {"id", "name", "email", "status", "created_at", "department", "role"},
    "products": {"id", "name", "category", "price", "status", "created_at"},
    "orders": {"id", "user_id", "product_id", "status", "created_at", "total"},
}

ALLOWED_TABLES = set(ALLOWED_COLUMNS.keys())

ALLOWED_OPERATORS = {
    "eq": "=",
    "neq": "!=",
    "gt": ">",
    "gte": ">=",
    "lt": "<",
    "lte": "<=",
    "like": "LIKE",
    "in": "IN",
    "is_null": "IS NULL",
    "is_not_null": "IS NOT NULL",
}

ALLOWED_SORT_DIRECTIONS = {"asc", "desc"}

MAX_LIMIT = 500
DEFAULT_LIMIT = 50


def get_db_password():
    """Retrieve database password from Secret Manager."""
    client = secretmanager.SecretManagerServiceClient()
    secret_name = os.environ.get("DB_PASSWORD_SECRET")
    if secret_name:
        response = client.access_secret_version(request={"name": secret_name})
        return response.payload.data.decode("UTF-8")
    return os.environ.get("DB_PASSWORD", "")


def get_connection():
    """Get or create a database connection."""
    global db_connection
    if db_connection is None or not db_connection.open:
        db_config = {
            "host": os.environ.get("DB_HOST", "127.0.0.1"),
            "port": int(os.environ.get("DB_PORT", 3306)),
            "user": os.environ.get("DB_USER", "app_reader"),
            "password": get_db_password(),
            "database": os.environ.get("DB_NAME", "app_db"),
            "charset": "utf8mb4",
            "cursorclass": pymysql.cursors.DictCursor,
            "connect_timeout": 10,
            "read_timeout": 30,
            # Use Unix socket for Cloud SQL in Cloud Functions
            "unix_socket": os.environ.get("DB_SOCKET", None),
        }
        # Remove None values
        db_config = {k: v for k, v in db_config.items() if v is not None}
        db_connection = pymysql.connect(**db_config)
    return db_connection


def validate_table(table_name):
    """Validate table name against whitelist."""
    if table_name not in ALLOWED_TABLES:
        raise ValueError(
            f"Invalid table: '{table_name}'. Allowed tables: {sorted(ALLOWED_TABLES)}"
        )
    return table_name


def validate_column(table_name, column_name):
    """Validate column name against whitelist for the given table."""
    allowed = ALLOWED_COLUMNS.get(table_name, set())
    if column_name not in allowed:
        raise ValueError(
            f"Invalid column: '{column_name}' for table '{table_name}'. "
            f"Allowed columns: {sorted(allowed)}"
        )
    return column_name


def validate_operator(operator):
    """Validate operator against whitelist."""
    if operator not in ALLOWED_OPERATORS:
        raise ValueError(
            f"Invalid operator: '{operator}'. Allowed operators: {sorted(ALLOWED_OPERATORS.keys())}"
        )
    return ALLOWED_OPERATORS[operator]


def build_secure_query(table, filters=None, select_columns=None,
                       sort_by=None, sort_dir="asc", limit=DEFAULT_LIMIT,
                       offset=0):
    """
    Build a parameterized SQL query securely.

    Uses whitelisting for table/column/operator names (which cannot be parameterized)
    and parameterized queries for all user-supplied VALUES.

    Args:
        table: Table name (validated against whitelist)
        filters: List of dicts with {column, operator, value}
        select_columns: List of column names to select
        sort_by: Column name to sort by
        sort_dir: Sort direction (asc/desc)
        limit: Number of results
        offset: Offset for pagination

    Returns:
        Tuple of (query_string, parameters_list)
    """
    # Validate table
    validated_table = validate_table(table)

    # Validate and build SELECT columns
    if select_columns:
        validated_columns = []
        for col in select_columns:
            validated_columns.append(
                f"`{validate_column(validated_table, col)}`"
            )
        columns_str = ", ".join(validated_columns)
    else:
        columns_str = "*"

    # Start building query - table name is whitelisted, safe to use directly
    query = f"SELECT {columns_str} FROM `{validated_table}`"
    params = []

    # Build WHERE clause with parameterized values
    if filters:
        where_clauses = []
        for f in filters:
            column = validate_column(validated_table, f["column"])
            sql_operator = validate_operator(f["operator"])

            if f["operator"] == "is_null":
                where_clauses.append(f"`{column}` IS NULL")
            elif f["operator"] == "is_not_null":
                where_clauses.append(f"`{column}` IS NOT NULL")
            elif f["operator"] == "in":
                values = f.get("value", [])
                if not isinstance(values, list) or len(values) == 0:
                    raise ValueError(
                        f"'in' operator requires a non-empty list of values for column '{column}'"
                    )
                if len(values) > 100:
                    raise ValueError(
                        f"'in' operator supports a maximum of 100 values"
                    )
                placeholders = ", ".join(["%s"] * len(values))
                where_clauses.append(f"`{column}` IN ({placeholders})")
                params.extend(values)
            elif f["operator"] == "like":
                # Escape LIKE wildcards in user input, then wrap with %
                value = f["value"]
                value = value.replace("\\", "\\\\").replace("%", "\\%").replace("_", "\\_")
                where_clauses.append(f"`{column}` LIKE %s")
                params.append(f"%{value}%")
            else:
                where_clauses.append(f"`{column}` {sql_operator} %s")
                params.append(f["value"])

        if where_clauses:
            query += " WHERE " + " AND ".join(where_clauses)

    # Add ORDER BY (column name is whitelisted)
    if sort_by:
        validated_sort_col = validate_column(validated_table, sort_by)
        validated_sort_dir = sort_dir.lower()
        if validated_sort_dir not in ALLOWED_SORT_DIRECTIONS:
            validated_sort_dir = "asc"
        query += f" ORDER BY `{validated_sort_col}` {validated_sort_dir.upper()}"

    # Add LIMIT and OFFSET with parameterized values
    validated_limit = min(int(limit), MAX_LIMIT)
    validated_offset = max(int(offset), 0)
    query += " LIMIT %s OFFSET %s"
    params.extend([validated_limit, validated_offset])

    return query, params


def build_count_query(table, filters=None):
    """Build a parameterized COUNT query for pagination metadata."""
    validated_table = validate_table(table)
    query = f"SELECT COUNT(*) as total FROM `{validated_table}`"
    params = []

    if filters:
        # Reuse the filter building logic
        full_query, full_params = build_secure_query(
            table, filters=filters, limit=1, offset=0
        )
        # Extract WHERE clause
        if " WHERE " in full_query:
            where_part = full_query.split(" WHERE ")[1].split(" ORDER BY ")[0].split(" LIMIT ")[0]
            query += f" WHERE {where_part}"
            # Exclude the LIMIT and OFFSET params (last 2)
            params = full_params[:-2]

    return query, params


def parse_request_filters(request_json):
    """Parse and validate filter parameters from request body."""
    filters = request_json.get("filters", [])
    validated_filters = []

    if not isinstance(filters, list):
        raise ValueError("'filters' must be a list")

    if len(filters) > 20:
        raise ValueError("Maximum of 20 filters allowed")

    for f in filters:
        if not isinstance(f, dict):
            raise ValueError("Each filter must be a dictionary")

        required_keys = {"column", "operator"}
        if not required_keys.issubset(f.keys()):
            raise ValueError(
                f"Each filter must have 'column' and 'operator' keys. Got: {list(f.keys())}"
            )

        operator = f["operator"]
        if operator not in ("is_null", "is_not_null") and "value" not in f:
            raise ValueError(
                f"Filter with operator '{operator}' requires a 'value' key"
            )

        validated_filters.append({
            "column": str(f["column"]),
            "operator": str(f["operator"]),
            "value": f.get("value"),
        })

    return validated_filters


def search_api(request):
    """
    Cloud Function entry point for the search API.

    Expected JSON request body:
    {
        "table": "users",
        "filters": [
            {"column": "status", "operator": "eq", "value": "active"},
            {"column": "name", "operator": "like", "value": "john"},
            {"column": "department", "operator": "in", "value": ["engineering", "product"]},
            {"column": "created_at", "operator": "gte", "value": "2024-01-01"}
        ],
        "select": ["id", "name", "email", "status"],
        "sort_by": "created_at",
        "sort_dir": "desc",
        "limit": 25,
        "offset": 0,
        "include_count": true
    }

    Supported operators: eq, neq, gt, gte, lt, lte, like, in, is_null, is_not_null
    """
    # Handle CORS preflight
    if request.method == "OPTIONS":
        headers = {
            "Access-Control-Allow-Origin": os.environ.get("ALLOWED_ORIGIN", "*"),
            "Access-Control-Allow-Methods": "POST",
            "Access-Control-Allow-Headers": "Content-Type, Authorization",
            "Access-Control-Max-Age": "3600",
        }
        return ("", 204, headers)

    cors_headers = {
        "Access-Control-Allow-Origin": os.environ.get("ALLOWED_ORIGIN", "*"),
        "Content-Type": "application/json",
    }

    try:
        # Only accept POST
        if request.method != "POST":
            return (
                json.dumps({"error": "Method not allowed. Use POST."}),
                405,
                cors_headers,
            )

        # Parse request
        request_json = request.get_json(silent=True)
        if not request_json:
            return (
                json.dumps({"error": "Request body must be valid JSON"}),
                400,
                cors_headers,
            )

        # Extract and validate parameters
        table = request_json.get("table")
        if not table:
            return (
                json.dumps({"error": "'table' is required"}),
                400,
                cors_headers,
            )

        filters = parse_request_filters(request_json)
        select_columns = request_json.get("select")
        sort_by = request_json.get("sort_by")
        sort_dir = request_json.get("sort_dir", "asc")
        limit = request_json.get("limit", DEFAULT_LIMIT)
        offset = request_json.get("offset", 0)
        include_count = request_json.get("include_count", False)

        # Validate numeric params
        try:
            limit = int(limit)
            offset = int(offset)
        except (ValueError, TypeError):
            return (
                json.dumps({"error": "'limit' and 'offset' must be integers"}),
                400,
                cors_headers,
            )

        # Build the secure parameterized query
        query, params = build_secure_query(
            table=table,
            filters=filters,
            select_columns=select_columns,
            sort_by=sort_by,
            sort_dir=sort_dir,
            limit=limit,
            offset=offset,
        )

        # Execute query
        conn = get_connection()
        results = []
        total_count = None

        try:
            with conn.cursor() as cursor:
                cursor.execute(query, params)
                results = cursor.fetchall()

                # Convert non-serializable types
                for row in results:
                    for key, value in row.items():
                        if hasattr(value, "isoformat"):
                            row[key] = value.isoformat()
                        elif isinstance(value, bytes):
                            row[key] = value.decode("utf-8", errors="replace")
                        elif isinstance(value, set):
                            row[key] = list(value)

                # Get total count for pagination
                if include_count:
                    count_query, count_params = build_count_query(table, filters)
                    cursor.execute(count_query, count_params)
                    count_result = cursor.fetchone()
                    total_count = count_result["total"] if count_result else 0

        except pymysql.OperationalError:
            # Connection may have timed out, retry once
            conn.ping(reconnect=True)
            with conn.cursor() as cursor:
                cursor.execute(query, params)
                results = cursor.fetchall()

                for row in results:
                    for key, value in row.items():
                        if hasattr(value, "isoformat"):
                            row[key] = value.isoformat()
                        elif isinstance(value, bytes):
                            row[key] = value.decode("utf-8", errors="replace")
                        elif isinstance(value, set):
                            row[key] = list(value)

                if include_count:
                    count_query, count_params = build_count_query(table, filters)
                    cursor.execute(count_query, count_params)
                    count_result = cursor.fetchone()
                    total_count = count_result["total"] if count_result else 0

        # Build response
        response = {
            "data": results,
            "metadata": {
                "table": table,
                "count": len(results),
                "limit": min(limit, MAX_LIMIT),
                "offset": offset,
            },
        }

        if total_count is not None:
            response["metadata"]["total"] = total_count
            response["metadata"]["has_more"] = (offset + len(results)) < total_count

        return (json.dumps(response, default=str), 200, cors_headers)

    except ValueError as e:
        return (
            json.dumps({"error": f"Validation error: {str(e)}"}),
            400,
            cors_headers,
        )
    except pymysql.MySQLError as e:
        # Log the actual error server-side, return generic message to client
        print(f"Database error: {e}")
        return (
            json.dumps({"error": "A database error occurred"}),
            500,
            cors_headers,
        )
    except Exception as e:
        print(f"Unexpected error: {e}")
        return (
            json.dumps({"error": "An internal error occurred"}),
            500,
            cors_headers,
        )